#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int arg0,
    __global const int* d_gpuWall,
    __global const int* src,
    __global int* dst,
    int cols,
    int rows,
    int t,
    int borderCols,
    int theHalo,
    __local int* local_min,
    __local int* local_src,
    __global int* d_outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    if (gid >= cols) return;

    int height = arg0;
    int current_row = t;

    for (int h = 0; h < height; h++) {
        int n = gid;

        int min_val = src[n];
        if (n > 0) {
            int left = src[n - 1];
            if (left < min_val) min_val = left;
        }
        if (n < cols - 1) {
            int right = src[n + 1];
            if (right < min_val) min_val = right;
        }

        int wall_index = (current_row + h + 1) * cols + n;
        dst[n] = d_gpuWall[wall_index - cols] + min_val;

        current_row++;
    }

    // Print timer message only once in the last iteration to match original output format
    if (gid == 0 && (t + arg0 >= rows - 1)) {
        printf("timer: 0\n");
    }
}
